export function UseTimeoutDemo() {
  const [isVisible, setIsVisible] = useState(false)
  const [delay, setDelay] = useState(3000)
  const [timeoutCount, setTimeoutCount] = useState(0)

  useTimeout(
    () => {
      if (isVisible) {
